mapper.select:
SELECT DTL.COMMON_CODE_DTL AS VALUE, DTL.COMMON_CODE_DTL_NAME AS LABEL FROM JPAS_DB.JPAS_TB_CMMN_CD CD, JPAS_DB.JPAS_TB_CMMN_CD_DTL DTL WHERE 1=1 AND CD.COMMON_CODE = DTL.COMMON_CODE AND CD.ACTIVE_YN = 'Y' AND DTL.ACTIVE_YN = 'Y'
AND DTL.COMMON_CODE = #{commonCode}
ORDER BY DTL.SORT_ORDER, DTL.COMMON_CODE
